import{_ as e,o as a,c as t,e as r}from"./app.7cad893a.js";const p={},o=r('<h1 id="openlayers自定义地图图层" tabindex="-1"><a class="header-anchor" href="#openlayers自定义地图图层" aria-hidden="true">#</a> openlayers自定义地图图层</h1><h2 id="使用maptiler可完成切图" tabindex="-1"><a class="header-anchor" href="#使用maptiler可完成切图" aria-hidden="true">#</a> 使用maptiler可完成切图</h2><blockquote><p>免费版会有水印，需要使用付费版<br><a href="/blog/utils/MapTilerPjb.rar">下载</a></p></blockquote><h2 id="瓦片地图汇总" tabindex="-1"><a class="header-anchor" href="#瓦片地图汇总" aria-hidden="true">#</a> 瓦片地图汇总</h2><p>参考：<code>https://www.cnblogs.com/HandyLi/p/11137367.html</code></p><blockquote><p>arcgis街道图<br> 默认图：<code>https://map.geoq.cn/ArcGIS/rest/services/ChinaOnlineCommunity/MapServer/tile/{z}/{y}/{x}</code><br> 灰色图：<code>https://map.geoq.cn/ArcGIS/rest/services/ChinaOnlineStreetGray/MapServer/tile/{z}/{y}/{x}</code><br> 深蓝夜色：<code>https://map.geoq.cn/ArcGIS/rest/services/ChinaOnlineStreetPurplishBlue/MapServer/tile/{z}/{y}/{x}</code></p><p>googlemap: lys参数可选值包括：h（街道图）、m（街道图）、p（街道图）、r（街道图）、s（影像无注记）、y（影像含注记）、t（地形图）<br><code>https://www.google.cn/maps/vt?lyrs=m@189&amp;gl=cn&amp;x={x}&amp;y={y}&amp;z={z}</code></p><p>高德地图<br> 街道（z&gt;=3才有数据）：<code>https://webrd01.is.autonavi.com/appmaptile?lang=zh_cn&amp;size=1&amp;scale=1&amp;style=8&amp;x={x}&amp;y={y}&amp;z={z}</code><br> 影像图：<code>https://webst01.is.autonavi.com/appmaptile?style=6&amp;x={x}&amp;y={y}&amp;z={z}</code></p><p>OSM 街道图（国外服务器，访问较慢）： <code>https://c.tile.openstreetmap.org/{z}/{x}/{y}.png</code><code>https://tile-b.openstreetmap.fr/hot/{z}/{x}/{y}.png</code></p></blockquote>',6),c=[o];function s(n,i){return a(),t("div",null,c)}const d=e(p,[["render",s],["__file","openlayers.html.vue"]]);export{d as default};
